1	import type { Element, XY } from '@bim-ai/core';
2	
3	export type SnapKind =
4	  | 'raw'
5	  | 'grid'
6	  | 'endpoint'
7	  /** EDT-05 — point where two infinite line extensions cross. */
8	  | 'intersection'
9	  /** EDT-05 — foot of perpendicular from cursor onto a line. */
10	  | 'perpendicular'
11	  /** EDT-05 — closest point on a line's infinite extension. */
12	  | 'extension'
13	  /** EDT-05 — tangent from cursor to a circular element. Reserved
14	   *  for when arc / circle geometry lands; today's snap engine
15	   *  produces no `tangent` candidates because no curved elements
16	   *  exist. The kind is exposed so downstream callers can render
17	   *  / hotkey-cycle past it without a future schema bump. */
18	  | 'tangent';
19	
20	export type SnapHit = { point: XY; kind: SnapKind };
21	
22	/** Two-point line segment used by the EDT-05 snap kinds. */
23	export interface SegmentLine {
24	  start: XY;
25	  end: XY;
26	}
27	
28	function dist2(ax: number, ay: number, bx: number, by: number) {
29	  const dx = ax - bx;
30	  const dy = ay - by;
31	  return dx * dx + dy * dy;
32	}
33	
34	function midpoint(a: XY, b: XY): XY {
35	  return { xMm: (a.xMm + b.xMm) / 2, yMm: (a.yMm + b.yMm) / 2 };
36	}
37	
38	export function orthoFromAnchor(cursor: XY, anchor: XY | undefined): XY {
39	  if (!anchor) return cursor;
40	  const dx = Math.abs(cursor.xMm - anchor.xMm);
41	  const dy = Math.abs(cursor.yMm - anchor.yMm);
42	  return dx >= dy ? { xMm: cursor.xMm, yMm: anchor.yMm } : { xMm: anchor.xMm, yMm: cursor.yMm };
43	}
44	
45	export function collectWallAnchors(
46	  els: Record<string, Element>,
47	  levelId: string | undefined,
48	): XY[] {
49	  const pts: XY[] = [];
50	
51	  for (const e of Object.values(els)) {
52	    if (e.kind === 'wall') {
53	      if (levelId && e.levelId !== levelId) continue;
54	
55	      pts.push(e.start, e.end, midpoint(e.start, e.end));
56	    } else if (e.kind === 'room') {
57	      if (levelId && e.levelId !== levelId) continue;
58	
59	      pts.push(...(e.outlineMm ?? []));
60	    } else if (e.kind === 'grid_line') {
61	      // Global grids omit level — level-scoped stay tied to slab
62	      if (e.levelId && levelId && e.levelId !== levelId) continue;
63	
64	      pts.push(e.start, e.end, midpoint(e.start, e.end));
65	    }
66	  }
67	
68	  return pts;
69	}
70	
71	/** EDT-05 — return wall + grid line segments scoped to a level so the
72	 *  snap engine can compute intersections / perpendiculars / extensions
73	 *  against them. */
74	export function collectSnapLines(
75	  els: Record<string, Element>,
76	  levelId: string | undefined,
77	): SegmentLine[] {
78	  const out: SegmentLine[] = [];
79	  for (const e of Object.values(els)) {
80	    if (e.kind === 'wall') {
81	      if (levelId && e.levelId !== levelId) continue;
82	      out.push({ start: e.start, end: e.end });
83	    } else if (e.kind === 'grid_line') {
84	      if (e.levelId && levelId && e.levelId !== levelId) continue;
85	      out.push({ start: e.start, end: e.end });
86	    }
87	  }
88	  return out;
89	}
90	
91	export function snapToGrid(p: XY, stepMm: number): XY {
92	  const s = Math.max(10, stepMm);
93	
94	  return {
95	    xMm: Math.round(p.xMm / s) * s,
96	    yMm: Math.round(p.yMm / s) * s,
97	  };
98	}
99	
100	/* ─── EDT-05 helpers ──────────────────────────────────────────────────── */
101	
102	/** Intersection of two infinite lines defined by segments. Returns
103	 *  null when the lines are parallel (or coincident). */
104	export function infiniteLineIntersection(a: SegmentLine, b: SegmentLine): XY | null {
105	  const x1 = a.start.xMm;
106	  const y1 = a.start.yMm;
107	  const x2 = a.end.xMm;
108	  const y2 = a.end.yMm;
109	  const x3 = b.start.xMm;
110	  const y3 = b.start.yMm;
111	  const x4 = b.end.xMm;
112	  const y4 = b.end.yMm;
113	  const denom = (x1 - x2) * (y3 - y4) - (y1 - y2) * (x3 - x4);
114	  if (denom === 0) return null;
115	  const t = ((x1 - x3) * (y3 - y4) - (y1 - y3) * (x3 - x4)) / denom;
116	  return {
117	    xMm: x1 + t * (x2 - x1),
118	    yMm: y1 + t * (y2 - y1),
119	  };
120	}
121	
122	/** Foot of perpendicular from `p` onto the infinite line through
123	 *  `line.start` and `line.end`. */
124	export function perpendicularFoot(p: XY, line: SegmentLine): XY | null {
125	  const dx = line.end.xMm - line.start.xMm;
126	  const dy = line.end.yMm - line.start.yMm;
127	  const denom = dx * dx + dy * dy;
128	  if (denom === 0) return null;
129	  const t = ((p.xMm - line.start.xMm) * dx + (p.yMm - line.start.yMm) * dy) / denom;
130	  return {
131	    xMm: line.start.xMm + t * dx,
132	    yMm: line.start.yMm + t * dy,
133	  };
134	}
135	
136	/** Project the cursor onto the line's infinite extension and only
137	 *  return a candidate when the projection falls *outside* the
138	 *  segment endpoints — that's the "extension" snap (an Endpoint snap
139	 *  would have already fired inside the segment). */
140	export function extensionPoint(p: XY, line: SegmentLine): XY | null {
141	  const foot = perpendicularFoot(p, line);
142	  if (!foot) return null;
143	  // Parametric position along the segment.
144	  const dx = line.end.xMm - line.start.xMm;
145	  const dy = line.end.yMm - line.start.yMm;
146	  const denom = dx * dx + dy * dy;
147	  const t = ((p.xMm - line.start.xMm) * dx + (p.yMm - line.start.yMm) * dy) / denom;
148	  if (t >= 0 && t <= 1) return null; // inside segment — caller has endpoint/perp coverage
149	  return foot;
150	}
151	
152	/** Multiple snap targets within radius — first is default; Tab-cycle can iterate. */
153	
154	export function snapPlanCandidates(opts: {
155	  cursor: XY;
156	  anchors: XY[];
157	
158	  gridStepMm: number;
159	  chainAnchor?: XY;
160	  snapMm: number;
161	
162	  orthoHold: boolean;
163	
164	  /** EDT-05 — line segments to compute intersection / perpendicular /
165	   *  extension snaps against. Optional for backward compatibility. */
166	  lines?: SegmentLine[];
167	}): SnapHit[] {
168	  const p = opts.orthoHold ? orthoFromAnchor(opts.cursor, opts.chainAnchor) : opts.cursor;
169	
170	  const gridPt = snapToGrid(p, opts.gridStepMm);
171	
172	  const tol2 = opts.snapMm * opts.snapMm;
173	
174	  const hits: SnapHit[] = [];
175	
176	  hits.push({ point: { xMm: gridPt.xMm, yMm: gridPt.yMm }, kind: 'grid' });
177	
178	  let bestAnch: XY | undefined;
179	
180	  let bestD = Infinity;
181	
182	  for (const a of opts.anchors) {
183	    const da = dist2(p.xMm, p.yMm, a.xMm, a.yMm);
184	
185	    if (da <= tol2 && da < bestD) {
186	      bestD = da;
187	
188	      bestAnch = a;
189	    }
190	  }
191	
192	  if (bestAnch) hits.unshift({ point: { xMm: bestAnch.xMm, yMm: bestAnch.yMm }, kind: 'endpoint' });
193	
194	  // EDT-05: intersection / perpendicular / extension candidates.
195	  if (opts.lines && opts.lines.length > 0) {
196	    // Intersection: pairwise infinite-line cross of every wall/grid pair.
197	    for (let i = 0; i < opts.lines.length; i++) {
198	      for (let j = i + 1; j < opts.lines.length; j++) {
199	        const cross = infiniteLineIntersection(opts.lines[i], opts.lines[j]);
200	        if (!cross) continue;
201	        if (dist2(p.xMm, p.yMm, cross.xMm, cross.yMm) <= tol2) {
202	          hits.push({ point: cross, kind: 'intersection' });
203	        }
204	      }
205	    }
206	    // Perpendicular: foot of perpendicular from cursor to each segment.
207	    for (const line of opts.lines) {
208	      const foot = perpendicularFoot(p, line);
209	      if (!foot) continue;
210	      if (dist2(p.xMm, p.yMm, foot.xMm, foot.yMm) <= tol2) {
211	        hits.push({ point: foot, kind: 'perpendicular' });
212	      }
213	    }
214	    // Extension: projection onto the infinite line outside the segment.
215	    for (const line of opts.lines) {
216	      const ext = extensionPoint(p, line);
217	      if (!ext) continue;
218	      if (dist2(p.xMm, p.yMm, ext.xMm, ext.yMm) <= tol2) {
219	        hits.push({ point: ext, kind: 'extension' });
220	      }
221	    }
222	  }
223	
224	  const seen = new Set<string>();
225	
226	  const out: SnapHit[] = [];
227	
228	  for (const h of hits) {
229	    const k = `${Math.round(h.point.xMm)}:${Math.round(h.point.yMm)}:${h.kind}`;
230	
231	    if (seen.has(k)) continue;
232	
233	    seen.add(k);
234	
235	    out.push(h);
236	  }
237	
238	  out.sort((a, b) => {
239	    // Endpoint > intersection > perpendicular > extension > grid > raw.
240	    // This matches Revit's "stronger" snap winning by kind, then
241	    // proximity inside the same kind.
242	    const rank = (k: SnapKind) =>
243	      k === 'endpoint'
244	        ? 0
245	        : k === 'intersection'
246	          ? 1
247	          : k === 'perpendicular'
248	            ? 2
249	            : k === 'extension'
250	              ? 3
251	              : k === 'tangent'
252	                ? 4
253	                : k === 'grid'
254	                  ? 5
255	                  : 6;
256	    const ra = rank(a.kind);
257	    const rb = rank(b.kind);
258	    if (ra !== rb) return ra - rb;
259	    const da = dist2(opts.cursor.xMm, opts.cursor.yMm, a.point.xMm, a.point.yMm);
260	    const db = dist2(opts.cursor.xMm, opts.cursor.yMm, b.point.xMm, b.point.yMm);
261	    return da - db;
262	  });
263	
264	  return out;
265	}
266	
267	export function snapPlanPoint(opts: Parameters<typeof snapPlanCandidates>[0]): SnapHit {
268	  const c = snapPlanCandidates(opts);
269	
270	  if (c.length) return c[0]!;
271	
272	  const p = opts.orthoHold ? orthoFromAnchor(opts.cursor, opts.chainAnchor) : opts.cursor;
273	
274	  return { point: { xMm: p.xMm, yMm: p.yMm }, kind: 'raw' };
275	}
