1	/**
2	 * EDT-05 — per-snap-type toggle persistence.
3	 *
4	 * Reads / writes a JSON blob in localStorage so user-toggled snap
5	 * preferences survive a page reload. Keys mirror `SnapKind` from
6	 * `snapEngine.ts`. Tangent is reserved for when curved geometry lands
7	 * but is exposed here so the toolbar checkbox does not need a future
8	 * schema bump.
9	 */
10	import type { SnapKind } from './snapEngine';
11	
12	export type ToggleableSnapKind =
13	  | 'endpoint'
14	  | 'midpoint'
15	  | 'intersection'
16	  | 'perpendicular'
17	  | 'extension'
18	  | 'grid';
19	
20	export type SnapSettings = Record<ToggleableSnapKind, boolean>;
21	
22	export const DEFAULT_SNAP_SETTINGS: SnapSettings = {
23	  endpoint: true,
24	  midpoint: true,
25	  intersection: true,
26	  perpendicular: true,
27	  extension: true,
28	  grid: true,
29	};
30	
31	const STORAGE_KEY = 'bim-ai.plan.snapSettings.v1';
32	
33	export function loadSnapSettings(storage: Storage | undefined = safeLocalStorage()): SnapSettings {
34	  if (!storage) return { ...DEFAULT_SNAP_SETTINGS };
35	  try {
36	    const raw = storage.getItem(STORAGE_KEY);
37	    if (!raw) return { ...DEFAULT_SNAP_SETTINGS };
38	    const parsed = JSON.parse(raw) as Partial<SnapSettings>;
39	    const out: SnapSettings = { ...DEFAULT_SNAP_SETTINGS };
40	    for (const k of Object.keys(DEFAULT_SNAP_SETTINGS) as ToggleableSnapKind[]) {
41	      if (typeof parsed[k] === 'boolean') out[k] = parsed[k];
42	    }
43	    return out;
44	  } catch {
45	    return { ...DEFAULT_SNAP_SETTINGS };
46	  }
47	}
48	
49	export function saveSnapSettings(
50	  next: SnapSettings,
51	  storage: Storage | undefined = safeLocalStorage(),
52	): void {
53	  if (!storage) return;
54	  try {
55	    storage.setItem(STORAGE_KEY, JSON.stringify(next));
56	  } catch {
57	    // Quota or privacy mode — ignore; the in-memory copy still works.
58	  }
59	}
60	
61	/** Filter snap candidates by the user's enabled-kind toggles. */
62	export function applySnapSettings<T extends { kind: SnapKind }>(
63	  candidates: T[],
64	  settings: SnapSettings,
65	): T[] {
66	  return candidates.filter((c) => {
67	    switch (c.kind) {
68	      case 'endpoint':
69	        return settings.endpoint;
70	      case 'intersection':
71	        return settings.intersection;
72	      case 'perpendicular':
73	        return settings.perpendicular;
74	      case 'extension':
75	        return settings.extension;
76	      case 'grid':
77	        return settings.grid;
78	      case 'tangent':
79	      case 'raw':
80	        return true;
81	    }
82	  });
83	}
84	
85	function safeLocalStorage(): Storage | undefined {
86	  try {
87	    return typeof window !== 'undefined' ? window.localStorage : undefined;
88	  } catch {
89	    return undefined;
90	  }
91	}
