1	/**
2	 * EDT-05 — Snap glyph layer.
3	 *
4	 * 2D HTML overlay rendered above the plan canvas. Draws a kind-specific
5	 * glyph at the active snap point (square / triangle / × / ⊥ / dot+dash)
6	 * plus a lower-left label. Pure presentational component — caller maps
7	 * world-mm to client-px and supplies the active SnapHit and the
8	 * extension source segment when the kind is `'extension'`.
9	 */
10	import type { SnapKind } from './snapEngine';
11	
12	const GLYPH_PX = 14;
13	
14	export interface SnapGlyphProps {
15	  /** Screen-space pixels (relative to the canvas root). */
16	  pxX: number;
17	  pxY: number;
18	  kind: SnapKind;
19	  /** Source-segment endpoint in screen px — only used for `extension`. */
20	  extensionFromPxX?: number;
21	  extensionFromPxY?: number;
22	  /** Render a faint highlight ring around the glyph (e.g. when this is
23	   *  the actively-selected candidate during Tab-cycle). */
24	  highlighted?: boolean;
25	}
26	
27	/** Returns the human label rendered in the lower-left readout. */
28	export function snapKindLabel(kind: SnapKind): string {
29	  switch (kind) {
30	    case 'endpoint':
31	      return 'endpoint';
32	    case 'intersection':
33	      return 'intersection';
34	    case 'perpendicular':
35	      return 'perpendicular';
36	    case 'extension':
37	      return 'extension';
38	    case 'tangent':
39	      return 'tangent';
40	    case 'grid':
41	      return 'grid';
42	    case 'raw':
43	      return '';
44	  }
45	}
46	
47	/** Single glyph at one snap point. */
48	export function SnapGlyph(props: SnapGlyphProps) {
49	  const { pxX, pxY, kind, extensionFromPxX, extensionFromPxY, highlighted = false } = props;
50	  const half = GLYPH_PX / 2;
51	  // SVG viewBox is centred at (pxX, pxY); we stretch to include the
52	  // extension dashed line back to source when present.
53	  const minX = Math.min(pxX - half - 2, extensionFromPxX ?? pxX - half - 2);
54	  const minY = Math.min(pxY - half - 2, extensionFromPxY ?? pxY - half - 2);
55	  const maxX = Math.max(pxX + half + 2, extensionFromPxX ?? pxX + half + 2);
56	  const maxY = Math.max(pxY + half + 2, extensionFromPxY ?? pxY + half + 2);
57	  const width = maxX - minX;
58	  const height = maxY - minY;
59	  const stroke = '#fcd34d'; // --draft-construction-blue
60	  const ring = highlighted ? (
61	    <circle
62	      data-testid={`snap-glyph-ring-${kind}`}
63	      cx={pxX}
64	      cy={pxY}
65	      r={GLYPH_PX}
66	      fill="none"
67	      stroke={stroke}
68	      strokeOpacity={0.45}
69	      strokeWidth={1}
70	    />
71	  ) : null;
72	  let glyph: React.ReactNode = null;
73	  switch (kind) {
74	    case 'endpoint':
75	      glyph = (
76	        <rect
77	          data-testid="snap-glyph-endpoint"
78	          x={pxX - half}
79	          y={pxY - half}
80	          width={GLYPH_PX}
81	          height={GLYPH_PX}
82	          fill="none"
83	          stroke={stroke}
84	          strokeWidth={1.5}
85	        />
86	      );
87	      break;
88	    case 'intersection':
89	      glyph = (
90	        <g data-testid="snap-glyph-intersection">
91	          <line
92	            x1={pxX - half}
93	            y1={pxY - half}
94	            x2={pxX + half}
95	            y2={pxY + half}
96	            stroke={stroke}
97	            strokeWidth={1.5}
98	          />
99	          <line
100	            x1={pxX - half}
101	            y1={pxY + half}
102	            x2={pxX + half}
103	            y2={pxY - half}
104	            stroke={stroke}
105	            strokeWidth={1.5}
106	          />
107	        </g>
108	      );
109	      break;
110	    case 'perpendicular':
111	      glyph = (
112	        <g data-testid="snap-glyph-perpendicular">
113	          {/* Vertical stroke + horizontal foot — Revit's ⊥ glyph. */}
114	          <line
115	            x1={pxX}
116	            y1={pxY - half}
117	            x2={pxX}
118	            y2={pxY + half}
119	            stroke={stroke}
120	            strokeWidth={1.5}
121	          />
122	          <line
123	            x1={pxX - half}
124	            y1={pxY + half}
125	            x2={pxX + half}
126	            y2={pxY + half}
127	            stroke={stroke}
128	            strokeWidth={1.5}
129	          />
130	        </g>
131	      );
132	      break;
133	    case 'extension': {
134	      const fromX = extensionFromPxX ?? pxX;
135	      const fromY = extensionFromPxY ?? pxY;
136	      glyph = (
137	        <g data-testid="snap-glyph-extension">
138	          <line
139	            x1={fromX}
140	            y1={fromY}
141	            x2={pxX}
142	            y2={pxY}
143	            stroke={stroke}
144	            strokeWidth={1}
145	            strokeDasharray="3 3"
146	          />
147	          <circle cx={pxX} cy={pxY} r={2.5} fill={stroke} />
148	        </g>
149	      );
150	      break;
151	    }
152	    case 'tangent':
153	      // Reserved — no curved geometry yet. Render the dot so a future
154	      // arc engine has a valid glyph hookup without an extra commit.
