  workplane: true,
  grid: true,
};

/** EDT-05 closeout — kinds shipped in the wave-04 closeout. Exported so
 *  callers can iterate the canonical set without depending on the
 *  literal string union. */
export const SNAP_KINDS: ToggleableSnapKind[] = [
  'endpoint',
  'midpoint',
  'intersection',
  'perpendicular',
  'extension',
