    { kind: 'extension', point: { xMm: 3, yMm: 3 } },
    { kind: 'grid', point: { xMm: 4, yMm: 4 } },
  ];

  it('drops the kinds the user has disabled', () => {
    const settings: SnapSettings = {
      ...DEFAULT_SNAP_SETTINGS,
      perpendicular: false,
      extension: false,
