  clampDragDelta,
  clear3dGripProviders,
  gripsFor,
  register3dGripProvider,
  wallGripProvider,
} from './grip3d';

const baseWall = {
  id: 'w-ssw',
  kind: 'wall' as const,
  start: { xMm: 0, yMm: 0 },
  end: { xMm: 5000, yMm: 0 },
  heightMm: 3000,
  baseElevationMm: 0,
  baseConstraintOffsetMm: 0,
  topConstraintOffsetMm: 0,
};

