  });

  test('clamps to max when over', () => {
    expect(clampDragDelta(900, { minMm: -500, maxMm: 500 })).toBe(500);
  });

  test('clamps to min when under', () => {
    expect(clampDragDelta(-900, { minMm: -500, maxMm: 500 })).toBe(-500);
  });

  test('treats NaN as zero', () => {
    expect(clampDragDelta(Number.NaN, { minMm: -10, maxMm: 10 })).toBe(0);
